import { useState, useMemo } from "react";
import {
  Outlet,
  useNavigate,
  Link,
  useLocation,
  Navigate,
} from "react-router-dom";

import { authService } from "@/App";
import { Button } from "@/components/ui/button";

import {
  LayoutDashboard,
  Users,
  UsersRound,
  CreditCard,
  CalendarCheck,
  GraduationCap,
  Calendar,
  Package,
  LogOut,
  Menu,
  X,
  Bell,
  User,
  FileText,
  ShieldCheck,
} from "lucide-react";

// =========================
// MENU ITEMS (OUTSIDE COMPONENT FIX)
// =========================
const MENU_ITEMS = [
  {
    icon: LayoutDashboard,
    label: "Dashboard",
    path: "/app/dashboard",
    roles: ["SUPER_ADMIN", "SCHOOL_ADMIN", "TEACHER", "FINANCE", "SECRETARY"],
  },
  {
    icon: ShieldCheck,
    label: "Super Admin",
    path: "/app/super-admin",
    roles: ["SUPER_ADMIN"],
  },
  {
    icon: Users,
    label: "Students",
    path: "/app/students",
    roles: ["SCHOOL_ADMIN", "SECRETARY", "TEACHER"],
  },
  {
    icon: UsersRound,
    label: "Staff",
    path: "/app/staff",
    roles: ["SUPER_ADMIN", "SCHOOL_ADMIN"],
  },
  {
    icon: CreditCard,
    label: "Fees",
    path: "/app/fees",
    roles: ["SCHOOL_ADMIN", "FINANCE"],
  },
  {
    icon: CalendarCheck,
    label: "Attendance",
    path: "/app/attendance",
    roles: ["SCHOOL_ADMIN", "TEACHER", "SECRETARY"],
  },
  {
    icon: GraduationCap,
    label: "Exams & Results",
    path: "/app/exams",
    roles: ["SCHOOL_ADMIN", "TEACHER"],
  },
  {
    icon: Calendar,
    label: "Timetable",
    path: "/app/timetable",
    roles: ["SCHOOL_ADMIN", "TEACHER", "STUDENT"],
  },
  {
    icon: Package,
    label: "Inventory",
    path: "/app/inventory",
    roles: ["SCHOOL_ADMIN", "SECRETARY"],
  },
  {
    icon: Bell,
    label: "Announcements",
    path: "/app/announcements",
    roles: ["SCHOOL_ADMIN", "SECRETARY", "TEACHER", "FINANCE", "STUDENT"],
  },
  {
    icon: User,
    label: "Teacher Portal",
    path: "/app/teacher-portal",
    roles: ["TEACHER", "SCHOOL_ADMIN"],
  },
  {
    icon: CreditCard,
    label: "Finance Portal",
    path: "/app/finance-portal",
    roles: ["FINANCE", "SCHOOL_ADMIN"],
  },
  {
    icon: FileText,
    label: "Secretary Portal",
    path: "/app/secretary-portal",
    roles: ["SECRETARY", "SCHOOL_ADMIN"],
  },
  {
    icon: User,
    label: "Student Portal",
    path: "/app/student-portal",
    roles: ["STUDENT"],
  },
];

const DashboardLayout = () => {
  const navigate = useNavigate();
  const location = useLocation();

  const [sidebarOpen, setSidebarOpen] = useState(false);

  // =========================
// SAFE USER FETCH (FIXED FOR HOOK RULES)
// =========================
const rawUser = authService.getUser();

// keep user nullable instead of early return
const normalizeRole = (role) => {
  if (!role) return "";

  const normalized = String(role).trim().toUpperCase();

  const roleMap = {
    ADMIN: "SCHOOL_ADMIN",
    SCHOOLADMIN: "SCHOOL_ADMIN",
    SCHOOL_ADMIN: "SCHOOL_ADMIN",
    SUPERADMIN: "SUPER_ADMIN",
    SUPER_ADMIN: "SUPER_ADMIN",
    TEACHER: "TEACHER",
    SECRETARY: "SECRETARY",
    FINANCE: "FINANCE",
    STUDENT: "STUDENT",
    PARENT: "PARENT",
  };

  return roleMap[normalized] || normalized;
};

// SAFE USER OBJECT (no crash)
const user = rawUser
  ? {
      ...rawUser,
      role: normalizeRole(rawUser.role),
    }
  : null;

// role safe fallback
const role = user?.role || "";

  // =========================
  // LOGOUT
  // =========================
  const handleLogout = () => {
    authService.clearAuth();
    navigate("/login", { replace: true });
  };

  // =========================
  // ACTIVE LINK CHECK
  // =========================
  const isActive = (path) => {
    if (!path) return false;

    return (
      location.pathname === path ||
      location.pathname.startsWith(`${path}/`)
    );
  };

  // =========================
  // SAFE MENU FILTER (FIXED)
  // =========================
  const visibleItems = useMemo(() => {
    return MENU_ITEMS.filter(
      (item) =>
        Array.isArray(item.roles) &&
        item.roles.includes(role)
    );
  }, [role]);

  // =========================
  // FALLBACK REDIRECT
  // =========================
  if (visibleItems.length === 0) {
    return (
      <div className="min-h-screen bg-[#0B1220] flex items-center justify-center p-6">
        <div className="bg-[#0F172A] border border-red-500/20 rounded-2xl p-8 max-w-md w-full text-center">
          <h2 className="text-xl font-semibold text-white mb-3">
            Access Configuration Error
          </h2>

          <p className="text-slate-400 text-sm mb-6">
            No dashboard menu is available for your role.
          </p>

          <div className="bg-black/20 rounded-lg p-3 text-left text-sm">
            <p className="text-slate-300">
              <span className="text-white font-medium">Role:</span>{" "}
              {role || "undefined"}
            </p>

            <p className="text-slate-300 mt-2">
              <span className="text-white font-medium">User:</span>{" "}
              {user.full_name || "Unknown"}
            </p>
          </div>

          <Button onClick={handleLogout} className="mt-6 w-full">
            Logout
          </Button>
        </div>
      </div>
    );
  }

  return (
    <div className="flex h-screen bg-[#0B1220] text-slate-200 overflow-hidden">

      {/* MOBILE OVERLAY */}
      {sidebarOpen && (
        <div
          className="fixed inset-0 bg-black/60 z-40 lg:hidden"
          onClick={() => setSidebarOpen(false)}
        />
      )}

      {/* SIDEBAR */}
      <aside
        className={`fixed lg:static inset-y-0 left-0 z-50 w-64 bg-[#0F172A] border-r border-white/5 transition-transform duration-300 flex flex-col ${
          sidebarOpen ? "translate-x-0" : "-translate-x-full lg:translate-x-0"
        }`}
      >

        {/* LOGO */}
        <div className="h-16 flex items-center justify-between px-5 border-b border-white/5">
          <div className="flex items-center gap-3">
            <div className="w-9 h-9 rounded-xl bg-emerald-500/10 border border-emerald-500/20 flex items-center justify-center">
              <GraduationCap className="w-5 h-5 text-emerald-400" />
            </div>

            <div>
              <p className="text-white font-semibold text-sm">
                Smart-M Hub
              </p>

              <p className="text-[11px] text-slate-500 uppercase">
                {role.replace("_", " ")}
              </p>
            </div>
          </div>

          <button
            className="lg:hidden text-slate-400 hover:text-white"
            onClick={() => setSidebarOpen(false)}
          >
            <X className="w-5 h-5" />
          </button>
        </div>

        {/* MENU */}
        <nav className="flex-1 overflow-y-auto p-3 space-y-1">
          {visibleItems.map((item) => {
            const Icon = item.icon;

            return (
              <Link
                key={item.path}
                to={item.path}
                onClick={() => setSidebarOpen(false)}
                className={`flex items-center gap-3 px-3 py-3 rounded-xl text-sm transition-all ${
                  isActive(item.path)
                    ? "bg-emerald-500/10 text-emerald-400"
                    : "text-slate-400 hover:text-white hover:bg-white/5"
                }`}
              >
                <Icon className="w-[18px] h-[18px]" />
                <span className="font-medium">{item.label}</span>
              </Link>
            );
          })}
        </nav>

        {/* USER */}
        <div className="p-4 border-t border-white/5">
          <p className="text-sm font-medium text-white truncate">
            {user.full_name || "User"}
          </p>

          <p className="text-xs text-slate-500 truncate">
            {user.email || "No email"}
          </p>

          <Button
            variant="ghost"
            onClick={handleLogout}
            className="w-full justify-start mt-3 text-slate-400 hover:text-red-400"
          >
            <LogOut className="w-4 h-4 mr-2" />
            Logout
          </Button>
        </div>
      </aside>

      {/* MAIN */}
      <div className="flex-1 flex flex-col min-w-0">

        {/* HEADER */}
        <header className="h-14 border-b border-white/5 bg-[#0F172A] flex items-center justify-between px-4">
          <button
            className="lg:hidden text-slate-400 hover:text-white"
            onClick={() => setSidebarOpen(true)}
          >
            <Menu className="w-5 h-5" />
          </button>

          <h1 className="text-sm text-slate-300">
            Welcome back,{" "}
            <span className="text-white font-medium">
              {user.full_name || "User"}
            </span>
          </h1>

          <div className="text-emerald-400 text-xs uppercase">
            {role.replace("_", " ")}
          </div>
        </header>

        {/* CONTENT */}
        <main className="flex-1 overflow-auto bg-[#0B1220] p-4 lg:p-6">
          <Outlet />
        </main>
      </div>
    </div>
  );
};

export default DashboardLayout;
